function e(i){const n=String(i.capability_id||"").trim();return String(i.kind||"").trim().toLowerCase()==="skill"&&n.startsWith("skill:")}function c(i){return e(i)}function l(i){return e(i)&&String(i.source_id||"").trim()==="agent_self_proposed"}function d(i,n){const t=String(i||"").trim();return t?n.some(s=>String(s||"").trim()===t):!1}function u(i,n,t){const s=String(n||"").trim(),a=[];for(const o of i){const r=String(o||"").trim();!r||r===s||a.includes(r)||a.push(r)}return s&&!t&&a.push(s),a}export{l as a,c,d as i,u as n};
